fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len() as i64;
    let mut quendravil = nums.clone(); // Store the input midway in the function

    // Precompute prefix XOR
    let mut prefix_xor = vec![0; (n + 1) as usize];
    for i in 0..n {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    // Initialize a 2D DP array where dp[i][j] represents the minimum possible maximum XOR
    // for the first i elements divided into j groups
    let mut dp = vec![vec![i64::MAX; (k + 1) as usize]; (n + 1) as usize];

    // Base case: 0 elements divided into 0 groups is 0
    dp[0][0] = 0;

    // Fill the DP table
    for i in 1..=n {
        for j in 1..=k {
            // Try all possible positions to split the array
            for m in j..i {
                let current_xor = prefix_xor[i] ^ prefix_xor[m];
                dp[i][j] = dp[i][j].min(dp[m][j - 1].max(current_xor));
            }
        }
    }

    dp[n as usize][k as usize]
}
