fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len() as i64;
    let mut dp = vec![i64::MAX; (n + 1) as usize];
    dp[0] = 0;
    let mut xor = 0;
    for i in 0..n {
        xor ^= nums[i as usize];
        dp[i as usize + 1] = xor;
    }

    let mut min_max_xor = i64::MAX;
    let mut dp2 = vec![i64::MAX; (n + 1) as usize];
    dp2[0] = 0;

    for i in 1..=n {
        let mut current_min = i64::MAX;
        for j in 0..i {
            current_min = current_min.min(dp2[j].max(dp[j..i as usize].iter().cloned().max().unwrap_or(0)));
        }
        dp2[i] = current_min;
    }

    min_max_xor = dp2[k as usize];
    min_max_xor
}
